using System;using System.Collections.Generic;using System.Linq;class A{static void Main(){var p=Console.ReadLine().Split(' ');int L=int.Parse(p[0]),C=int.Parse(p[1]);var G=new char[L][];int r=0,c=0;var T=new List<(int,int)>();for(int i=0;i<L;i++){G[i]=Console.ReadLine().ToCharArray();for(int j=0;j<C;j++){if(G[i][j]=='@'){r=i;c=j;}if(G[i][j]=='T')T.Add((i,j));}}int[]dr={1,0,-1,0},dc={0,1,0,-1};string[]nm={"SOUTH","EAST","NORTH","WEST"};var ds="SENW";int d=0,b=0,v=0;var P=new List<string>();var V=new HashSet<string>();for(;;){var k=$"{r},{c},{d},{b},{v},{string.Join("",G.Select(x=>new string(x)))}";if(!V.Add(k)){Console.WriteLine("LOOP");return;}var h=G[r][c];for(int i=0;i<4;i++)if(h==ds[i])d=i;if(h=='B')b^=1;if(h=='I')v^=1;if(h=='T'){var t=T.First(x=>x.Item1!=r||x.Item2!=c);r=t.Item1;c=t.Item2;}int[]q=v>0?new[]{3,2,1,0}:new[]{0,1,2,3};int nr=r+dr[d],nc=c+dc[d];var e=G[nr][nc];if(e=='#'||(e=='X'&&b==0))foreach(var i in q){nr=r+dr[i];nc=c+dc[i];e=G[nr][nc];if(e!='#'&&(e!='X'||b>0)){d=i;break;}}r=nr;c=nc;P.Add(nm[d]);if(G[r][c]=='X'&&b>0)G[r][c]=' ';if(G[r][c]=='$'){Console.Write(string.Join("\n",P)+"\n");return;}}}}